### Per-Test Logging
```rust
fn stress_test_with_logging<F: FnOnce(&mut ConformanceWorkspace) -> Result<()>>(
    test_name: &str,
    setup: F,
) -> Result<()> {
    let start = std::time::Instant::now();
    info!("stress_test_{}: BEGIN", test_name);

    let workspace = ConformanceWorkspace::new(test_name)?;
    info!("stress_test_{}: workspace created at {:?}", test_name, workspace.temp_dir.path());

    // Run setup phase
    let setup_start = Instant::now();
    setup(&mut workspace)?;
    let setup_duration = setup_start.elapsed();
    info!("stress_test_{}: setup completed in {:?}", test_name, setup_duration);

    // Memory before test
    let mem_before = get_process_memory_mb();
    info!("stress_test_{}: memory_before_mb={:.1}", test_name, mem_before);

    // Run br
    let br_start = Instant::now();
    let br_output = workspace.run_br(&[/* cmd */])?;
    let br_duration = br_start.elapsed();

    // Run bd
    let bd_start = Instant::now();
    let bd_output = workspace.run_bd(&[/* cmd */])?;
    let bd_duration = bd_start.elapsed();

    // Memory after test
    let mem_after = get_process_memory_mb();
    let mem_delta = mem_after - mem_before;

    // Log comprehensive metrics
    info!("stress_test_{}: br_exit={} br_time={:?}", test_name, br_output.status.code().unwrap_or(-1), br_duration);
    info!("stress_test_{}: bd_exit={} bd_time={:?}", test_name, bd_output.status.code().unwrap_or(-1), bd_duration);
    info!("stress_test_{}: memory_delta_mb={:.1}", test_name, mem_delta);
    info!("stress_test_{}: speedup={:.2}x", test_name, bd_duration.as_millis() as f64 / br_duration.as_millis().max(1) as f64);

    let elapsed = start.elapsed();
    info!("stress_test_{}: END total_time={:?}", test_name, elapsed);

    Ok(())
}
```

